"""family_fp16_6 - FLOAT16-intermediate rebuilds of memory-dominated incumbents.

Slice fp16_targets.json[6::7].  Each incumbent (out_p5/onnx/taskNNN.onnx) is an
EXACT float32 solver whose cost is dominated by [1,10,30,30] float32 intermediates
(4 bytes/elem).  Because the grader only thresholds (output > 0), the identical
computation runs in float16 with byte-identical (>0) results, halving the dominant
intermediate-memory term (cost = params + memory).

Construction (hand-built graph surgery, NOT onnxconverter_common auto-convert,
which yields non-SSA / mixed-type graphs the grader rejects):
  * Cast the float32 `input` -> float16 once at the top; rewrite every consumer.
  * Rebuild every float initializer / Constant in float16 (values clipped to the
    fp16 range so 1e6-style masking sentinels stay finite and still dominate).
  * Retarget every intermediate Cast-to-float32 to Cast-to-float16.
  * Keep each op's inputs a single dtype; pure-int / pure-bool tensors (ArgMax
    indices, Greater/Less/And/Equal masks, Slice/Reshape shapes, and opset-10
    Resize `scales`, which must remain tensor(float)) are left untouched.
  * The graph `output` is declared float16 (the grader thresholds (output>0), so
    the float width is irrelevant to correctness and it avoids a final Cast).

fp16 is EXACT for integers < 2048; every ReduceSum here is over <=900 cells and
every count / coordinate stays small, so the lowering is numerically exact.  Only
cost-reducing rebuilds are shipped: for tiny incumbents that slice the input
immediately, the one-off input->fp16 cast (a full [1,10,30,30] tensor) would
outweigh the halving, so those are not lowered.  Task 374 encodes positions as
values up to ~1e5 that fp16 cannot represent and is likewise excluded.

Detection is behavioural + self-contained: each embedded float16 graph is run via
onnxruntime on the task's train+test pairs and proposed only when it reproduces
every pair EXACTLY after the (>0) threshold (offline it was additionally validated
byte-identical against the incumbent on all arc-gen pairs), so wrong tasks never
fire and it generalises without memorising example contents.
"""
from __future__ import annotations

import base64
import gzip

import numpy as np
import onnx

try:
    import onnxruntime as _ort
except Exception:  # pragma: no cover
    _ort = None

# task -> {variant_tag: gzip+base64(float16 onnx)}
_MODELS = {'9': {'h': ''}, '22': {'h': ''}, '36': {'h': ''}, '69': {'h': ''}, '105': {'h': ''}, '117': {'h': ''}, '163': {'h': ''}, '175': {'h': ''}, '188': {'h': ''}, '224': {'h': ''}, '240': {'h': ''}, '268': {'h': ''}, '288': {'h': ''}, '300': {'h': ''}, '308': {'h': ''}, '325': {'h': ''}, '354': {'h': ''}, '384': {'h': ''}, '396': {'h': ''}, '59': {'h': ''}, '107': {'h': ''}, '154': {'h': ''}, '271': {'h': ''}, '333': {'h': ''}, '177': {'h': ''}, '71': {'h': ''}}

_SESS = {}


def _raw(t, tag):
    return gzip.decompress(base64.b64decode(_MODELS[t][tag]))


def _session(t, tag):
    key = (t, tag)
    s = _SESS.get(key)
    if s is None:
        so = _ort.SessionOptions()
        so.graph_optimization_level = _ort.GraphOptimizationLevel.ORT_DISABLE_ALL
        so.log_severity_level = 3
        s = _ort.InferenceSession(_raw(t, tag), so)
        _SESS[key] = s
    return s


def _onehot(grid):
    g = np.asarray(grid, dtype=np.int64)
    h, w = g.shape
    x = np.zeros((1, 10, 30, 30), dtype=np.float32)
    for r in range(h):
        row = g[r]
        for c in range(w):
            x[0, int(row[c]), r, c] = 1.0
    return x


def candidates(examples):
    if _ort is None:
        return []
    data = []
    for k in ("train", "test"):
        for e in examples.get(k, []) or []:
            gi = np.asarray(e["input"]); go = np.asarray(e["output"])
            if gi.ndim != 2 or go.ndim != 2:
                continue
            if max(gi.shape) > 30 or max(go.shape) > 30:
                continue
            data.append((_onehot(gi), _onehot(go)))
    if not data:
        return []
    out = []
    for t, variants in _MODELS.items():
        for tag in variants:
            try:
                sess = _session(t, tag)
            except Exception:
                continue
            ok = True
            for x, tg in data:
                try:
                    y = np.asarray(sess.run(["output"], {"input": x})[0])
                except Exception:
                    ok = False
                    break
                yb = (y > 0.0)
                if yb.shape != tg.shape or not np.array_equal(yb, tg > 0.0):
                    ok = False
                    break
            if ok:
                try:
                    out.append((f"fp16_{t}_{tag}", onnx.load_from_string(_raw(t, tag))))
                except Exception:
                    pass
    return out

